const getXsrfToken = (): string | null => {
  const match = document.cookie.split('; ').find(c => c.startsWith('xsrfToken='));
  if (!match) return null;
  const value = match.split('=')[1];
  return value ? decodeURIComponent(value) : null;
};
```
